// Test stackalloc with Span<nint> and Span<nuint>

// nint (signed native-sized integer)
Span<nint> signed = stackalloc nint[4];
for (int i = 0; i < signed.Length; i++)
    signed[i] = i * 10;

Console.WriteLine($"Span<nint> length: {signed.Length}, element size: {sizeof(nint)} bytes");
for (int i = 0; i < signed.Length; i++)
    Console.WriteLine($"  signed[{i}] = {signed[i]}");

// nuint (unsigned native-sized integer)
Span<nuint> unsigned = stackalloc nuint[4];
for (int i = 0; i < unsigned.Length; i++)
    unsigned[i] = (nuint)(i * 100);

Console.WriteLine($"Span<nuint> length: {unsigned.Length}, element size: {sizeof(nuint)} bytes");
for (int i = 0; i < unsigned.Length; i++)
    Console.WriteLine($"  unsigned[{i}] = {unsigned[i]}");

Console.WriteLine("Success — stackalloc Span<nint> and Span<nuint> both work!");

